+
+impl PaneView {
+    fn from_record(r: PaneRecord, redactor: &Redactor) -> Self {
+        Self {
+            pane_id: r.pane_id,
+            pane_uuid: r.pane_uuid,
+            domain: r.domain,
+            title: r.title.map(|t| redactor.redact(&t)),
+            cwd: r.cwd.map(|c| redactor.redact(&c)),
+            window_id: r.window_id,
+            tab_id: r.tab_id,
+            first_seen_at: r.first_seen_at,
