+#[derive(Serialize)]
+struct EventView {
+    id: i64,
+    pane_id: u64,
+    rule_id: String,
+    event_type: String,
+    severity: String,
+    confidence: f64,
+    #[serde(skip_serializing_if = "Option::is_none")]
