+fn build_app(storage: Option<StorageHandle>) -> App {
+    let state = AppState {
+        storage,
+        redactor: Arc::new(Redactor::new()),
+    };
+
+    App::builder()
+        .middleware(RequestSpanLogger::default())
+        .middleware(StateInjector { state })
+        .route(
+            "/health",
